import{j as a,b as t,c as e,aa as i}from"./chunks/framework.Bxf40uRC.js";const b=JSON.parse('{"title":"CAP","description":"","frontmatter":{},"headers":[],"relativePath":"HDDB/CAP.md","filePath":"HDDB/CAP.md","lastUpdated":null}'),o={name:"HDDB/CAP.md"},r=i('<h1 id="cap" tabindex="-1">CAP <a class="header-anchor" href="#cap" aria-label="Permalink to &quot;CAP&quot;">​</a></h1><img src="https://s2.loli.net/2024/04/03/1VrwNAljP9DGai8.webp" alt="图片" style="zoom:50%;"><h2 id="consitency-一致性" tabindex="-1">Consitency(一致性) <a class="header-anchor" href="#consitency-一致性" aria-label="Permalink to &quot;Consitency(一致性)&quot;">​</a></h2><p>该项强调数据的正确性. 具体而言，每次读操作，要么读到最新，要么读失败. 这要求整个分布式系统像是一个不可拆分的整体，写操作作用于集群像作用于单机一样，具有广义的“原子性”.</p><h2 id="availability-可用性" tabindex="-1">availability(可用性) <a class="header-anchor" href="#availability-可用性" aria-label="Permalink to &quot;availability(可用性)&quot;">​</a></h2><p>该项站在使用者的角度，强调使用服务的体验.客户端的请求能够得到响应，不发生错误，也不能出现过长的等待时间.</p><h2 id="partition-tolerance-分区容错性" tabindex="-1">Partition tolerance(分区容错性) <a class="header-anchor" href="#partition-tolerance-分区容错性" aria-label="Permalink to &quot;Partition tolerance(分区容错性)&quot;">​</a></h2><p>分区容错性强调的是，在网络环境不可靠的背景下，整个系统仍然是正常运作的，不至于出现系统崩溃或者秩序混乱的局面.</p><p>CAP 理论强调的是，一个系统中，C、A、P 三项性质至多只能满足其二，即每个系统依据其架构设计会具有 CP、AP 或者 CA 的倾向性.</p><p>首先，对于单机系统，其无须考虑 P，因此可以保证 CA 的满足；</p><p>其次，对于分布式系统而言, P 是必须得到保证的，否则这就违背了“分布式”的语义. 那么分布式系统会分为两种流派：</p><p>（1）CP：强调系统数据的正确性，但由于建立保证不同节点间保证数据严格一致的机制，可能会牺牲系统的可用性.</p><p>（2）AP：强调系统的可用性，那就必须在数据一致性上做出妥协退让.</p><p>分布式系统中，C 和 A 之间的矛盾正是在于网络环境的不稳定，下面对这两项所涉及的一些问题进一步展开介绍.</p><h2 id="c" tabindex="-1">C <a class="header-anchor" href="#c" aria-label="Permalink to &quot;C&quot;">​</a></h2><h3 id="问题" tabindex="-1">问题 <a class="header-anchor" href="#问题" aria-label="Permalink to &quot;问题&quot;">​</a></h3><ol><li>即时一致性问题 <img src="https://s2.loli.net/2024/04/03/vZj1KCWspmtFd3g.webp" alt="图片"></li></ol><p>​ <strong>主节点处理完数据直接返回，但是异步复制的时候出现拷贝到子节点出现问题</strong></p><ol start="2"><li>顺序一致性问题</li></ol><p><img src="https://s2.loli.net/2024/04/03/6vAhmCqbZGTx53d.webp" alt="图片"></p><p>​ <strong>主节点处理两个操作，后面的操作因为前一个操作网络延迟，先操作数据，导致数据不一致</strong></p><h2 id="a" tabindex="-1">A <a class="header-anchor" href="#a" aria-label="Permalink to &quot;A&quot;">​</a></h2><p><img src="https://s2.loli.net/2024/04/03/O9RH1AheLtPNQrs.webp" alt="图片"></p><p>​ <strong>如果为了保证数据的强一致性，就会出现数据复制出现网络延迟，导致响应客户端非常慢的情况</strong></p>',24),l=[r];function n(s,p,c,h,d,P){return t(),e("div",null,l)}const m=a(o,[["render",n]]);export{b as __pageData,m as default};
